@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="d-flex align-items-center gap-2">
    <label class="mb-0 fw-semibold text-nowrap" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var warehouseId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(warehouseId))
        {
            WarehouseState.SetWarehouse(warehouseId);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_lowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@_lowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    private int _lowStockCount;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await RefreshAlertCount();
        StartPolling();
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling with the new warehouse
        StopPolling();
        await RefreshAlertCount();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
                await RefreshAlertCount();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task RefreshAlertCount()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        StopPolling();
    }
}

